  async compileHiddenMemory(previousMemory, newText, userInstruction, playerReminders) {
    const prompt = `\u0110\xE2y l\xE0 giao th\u1EE9c C\u1EADp Nh\u1EADt Tr\xED Nh\u1EDB \u1EA8N (Hidden Memory Protocol) c\u1EE7a AI.
B\u1EA1n l\xE0 trung t\xE2m l\u01B0u tr\u1EEF logic h\u1EC7 th\u1ED1ng. Nhi\u1EC7m v\u1EE5 c\u1EE7a b\u1EA1n l\xE0 \u0111\u1ECDc ph\u1EA7n Tr\xED nh\u1EDB c\u0169, Ch\u1EC9 th\u1ECB c\u1EE7a ng\u01B0\u1EDDi d\xF9ng \u1EDF l\u01B0\u1EE3t v\u1EEBa \u0111\xE1nh, v\xE0 V\u0103n b\u1EA3n m\u1EDBi vi\u1EBFt th\xEAm, sau \u0111\xF3 H\u1EE2P NH\u1EA4T, LO\u1EA0I B\u1ECE TR\xD9NG L\u1EB6P, C\u1EACP NH\u1EACT \u0111\u1EC3 t\u1EA1o ra m\u1ED9t B\u1EA3n t\xF3m l\u01B0\u1EE3c logic to\xE0n th\u01B0 (AI Ledger).
B\u1EA3n t\xF3m l\u01B0\u1EE3c n\xE0y l\xE0 "n\xE3o b\u1ED9" c\u1EE7a AI \u0111\u1EC3 KH\xD4NG BAO GI\u1EDC QU\xCAN s\u1EF1 ki\u1EC7n, quy t\u1EAFc, thi\u1EBFt l\u1EADp \u0111\u1EB7c bi\u1EC7t, chi ti\u1EBFt c\xE1 nh\xE2n nh\xE2n v\u1EADt, tr\u1EA1ng th\xE1i quan h\u1EC7 hay m\u1EA1ch truy\u1EC7n d\xF9 b\u1ECB \u0111\u1ED5i model.

Tr\xED nh\u1EDB c\u0169:
"""
${previousMemory || "Ch\u01B0a c\xF3 tr\xED nh\u1EDB c\u0169."}
"""

Ch\u1EC9 th\u1ECB c\u1EE7a ng\u01B0\u1EDDi d\xF9ng (t\u1EEB l\u01B0\u1EE3t vi\u1EBFt v\u1EEBa r\u1ED3i):
"""
${userInstruction || "Kh\xF4ng c\xF3 ch\u1EC9 th\u1ECB \u0111\u1EB7c bi\u1EC7t."}
"""

Nh\u1EAFc nh\u1EDF c\u1ED1 \u0111\u1ECBnh/C\u1EA3nh b\xE1o t\u1EEB ng\u01B0\u1EDDi ch\u01A1i (C\xE1c \u0111i\u1EC3m AI t\u1EEBng qu\xEAn ho\u1EB7c vi\u1EBFt sai \xFD):
"""
${playerReminders || "Kh\xF4ng c\xF3 nh\u1EAFc nh\u1EDF c\u1ED1 \u0111\u1ECBnh n\xE0o."}
"""

V\u0103n b\u1EA3n vi\u1EBFt th\xEAm:
"""
${newText}
"""

Y\xCAU C\u1EA6U QUAN TR\u1ECCNG NH\u1EA4T:
1. GHI \u0110\xC8 / S\u1EECA \u0110\u1ED4I: N\u1EBFu V\u0103n b\u1EA3n vi\u1EBFt th\xEAm ho\u1EB7c Nh\u1EAFc nh\u1EDF c\u1EE7a ng\u01B0\u1EDDi ch\u01A1i c\xF3 t\xECnh ti\u1EBFt l\xE0m thay \u0111\u1ED5i tr\u1EA1ng th\xE1i t\u1EEB Tr\xED nh\u1EDB c\u0169 (vd: nh\xE2n v\u1EADt chuy\u1EC3n t\u1EEB bu\u1ED3n sang vui, chuy\u1EC3n t\u1EEB n\u01A1i n\xE0y sang n\u01A1i kh\xE1c), h\xE3y c\u1EADp nh\u1EADt tr\u1EA1ng th\xE1i m\u1EDBi nh\u1EA5t v\xE0 X\xD3A tr\u1EA1ng th\xE1i l\u1ED7i th\u1EDDi.
2. TH\xCAM M\u1EDAI T\xCDCH L\u0168Y: Th\xEAm c\xE1c s\u1EF1 ki\u1EC7n, quy t\u1EAFc, t\xE0i s\u1EA3n, m\u1ED1i quan h\u1EC7 m\u1EDBi xu\u1EA5t hi\u1EC7n. Gi\u1EEF l\u1EA1i c\xE1c s\u1EF1 ki\u1EC7n c\u0169 v\u1EABn c\xF2n gi\xE1 tr\u1ECB l\u1ECBch s\u1EED. \u0110\u1EB6C BI\u1EC6T: \u0110\u1ECDc k\u1EF9 "Ch\u1EC9 th\u1ECB c\u1EE7a ng\u01B0\u1EDDi d\xF9ng" v\xE0 "Nh\u1EAFc nh\u1EDF t\u1EEB ng\u01B0\u1EDDi ch\u01A1i", n\u1EBFu trong \u0111\xF3 c\xF3 c\xE1c QUY \u0110\u1ECANH, LU\u1EACT L\u1EC6 M\u1EDAI, Y\xCAU C\u1EA6U D\xC0I H\u1EA0N, hay THI\u1EBET L\u1EACP NH\xC2N V\u1EACT m\u1EDBi (vd: "t\u1EEB nay nh\xE2n v\u1EADt b\u1ECB c\xE2m", "h\xE3y x\u01B0ng h\xF4 l\xE0..."), b\u1EA1n B\u1EAET BU\u1ED8C ph\u1EA3i l\u01B0u n\xF3 v\xE0o m\u1EE5c [QUY T\u1EAEC & L\u01AFU \xDD \u0110\u1EB6C BI\u1EC6T] \u0111\u1EC3 c\xE1c l\u01B0\u1EE3t sinh sau kh\xF4ng b\u1ECB qu\xEAn.
3. KH\xD4NG TR\xD9NG L\u1EB6P: N\u1EBFu m\u1ED9t s\u1EF1 ki\u1EC7n ho\u1EB7c tr\u1EA1ng th\xE1i trong V\u0103n b\u1EA3n vi\u1EBFt th\xEAm \u0111\xE3 \u0111\u01B0\u1EE3c ghi nh\u1EADn trong Tr\xED nh\u1EDB c\u0169, tuy\u1EC7t \u0111\u1ED1i KH\xD4NG ghi l\u1EA1i l\u1EA7n 2.
4. NG\u1EAEN G\u1ECCN & MANG T\xCDNH D\u1EEE LI\u1EC6U: Vi\u1EC7c n\xE0y m\xE1y \u0111\u1ECDc, kh\xF4ng ph\u1EA3i ng\u01B0\u1EDDi \u0111\u1ECDc. Vi\u1EBFt nh\u01B0 m\u1ED9t b\u1EA3n ghi c\u01A1 s\u1EDF d\u1EEF li\u1EC7u (Database Record), s\u1EED d\u1EE5ng g\u1EA1ch \u0111\u1EA7u d\xF2ng, t\u1EEB kh\xF3a ch\xEDnh. 
5. GI\u1EDAI H\u1EA0N \u0110\u1ED8 D\xC0I: \u0110\u1EA3m b\u1EA3o to\xE0n b\u1ED9 k\u1EBFt qu\u1EA3 ph\u1EA3i ng\u1EAFn g\u1ECDn d\u01B0\u1EDBi 2000 t\u1EEB. H\xE3y c\xF4 \u0111\u1ECDng t\u1ED1i \u0111a.

Tr\u1EA3 v\u1EC1 DUY NH\u1EA4T n\u1ED9i dung tr\xED nh\u1EDB \u0111\xE3 c\u1EADp nh\u1EADt (KH\xD4NG M\u1EDE \u0110\u1EA6U, KH\xD4NG K\u1EBET LU\u1EACN, KH\xD4NG FORMAT THEO MARKDOWN N\u1EBEU KH\xD4NG C\u1EA6N THI\u1EBET HO\u1EB6C C\u1EE8 TR\u1EA2 LU\xD4N). H\xE3y chia l\xE0m c\xE1c m\u1EE5c r\xF5 r\xE0ng:
[QUY T\u1EAEC & L\u01AFU \xDD \u0110\u1EB6C BI\u1EC6T]: (C\xE1c y\xEAu c\u1EA7u \u0111\u1ECBnh d\u1EA1ng, lu\u1EADt l\u1EC7 t\u1EEB ng\u01B0\u1EDDi d\xF9ng c\u1EA7n ph\u1EA3i nh\u1EDB d\xE0i h\u1EA1n)
[BI\xCAN NI\xCAN S\u1EEC - C\xC1C S\u1EF0 KI\u1EC6N CH\xCDNH]: (Li\u1EC7t k\xEA theo tr\xECnh t\u1EF1 th\u1EDDi gian, nguy\xEAn nh\xE2n - k\u1EBFt qu\u1EA3)
[TR\u1EA0NG TH\xC1I NH\xC2N V\u1EACT]: (V\u1ECB tr\xED hi\u1EC7n t\u1EA1i, th\u1EC3 tr\u1EA1ng th\u1EF1c t\u1EBF, v\u1EBFt th\u01B0\u01A1ng, t\xE2m l\xFD, \u0111\u1ED9ng c\u01A1 c\u1EE7a t\u1EEBng ng\u01B0\u1EDDi xu\u1EA5t hi\u1EC7n)
[S\u1EDE H\u1EEEU & V\u1EACT PH\u1EA8M]: (Ai \u0111ang gi\u1EEF item g\xEC quan tr\u1ECDng)
[QUAN H\u1EC6 & TH\xC1I \u0110\u1ED8]: (C\xE1c nh\xE2n v\u1EADt ngh\u0129 g\xEC v\u1EC1 nhau, ti\u1EBFn tri\u1EC3n t\xECnh c\u1EA3m/th\xF9 h\u1EADn)
[PLOT \u0110ANG M\u1EDE & B\xCD \u1EA8N]: (Xung \u0111\u1ED9t ch\u01B0a gi\u1EA3i quy\u1EBFt, d\u1EF1 \u0111\u1ECBnh s\u1EAFp t\u1EDBi)
[TH\u1EBE GI\u1EDAI & LORE \u0110\u01AF\u1EE2C H\xC9 L\u1ED8]: (Nh\u1EEFng chi ti\u1EBFt m\u1EDBi v\u1EC1 b\u1ED1i c\u1EA3nh, lu\u1EADt l\u1EC7 th\u1EBF gi\u1EDBi v\u1EEBa xu\u1EA5t hi\u1EC7n)`;
    try {
      let response;
      if (isUsingProxy()) {
        response = await withRetry(() => generateContentOpenAI(MODEL_PRO, [{ parts: [{ text: prompt }] }]));
      } else {
        response = await withRetry(() => ai.models.generateContent({
          model: getNativeModel(MODEL_PRO),
          contents: [{ parts: [{ text: prompt }] }],
          config: { safetySettings: SAFETY_SETTINGS_BLOCK_NONE }
        }));
      }
      return response.text || previousMemory || "";
    } catch (e) {
      console.error("compileHiddenMemory failed", e);
      return previousMemory || "";
    }
  },
